from crewai import Agent, Task
from collections import defaultdict

def detect_delegation_loops(crew):
    task_history = defaultdict(list)

    def loop_callback(task: Task, agent: Agent, output):
        task_history[(task.description[:50], agent.name)].append(output)
        # Flag loops: same task+agent > 3 executions
        if len(task_history[(task.description[:50], agent.name)]) > 3:
            print(f'🚨 DELEGATION LOOP: {agent.name} repeated task 4+ times')
            return {'loop_detected': True, 'count': len(task_history[(task.description[:50], agent.name)])}

    return loop_callback

import re
from crewai_tools import tool

def detect_hallucinated_tools(task_output):
    # Common hallucination patterns
    hallucination_patterns = [
        r'API returned error|404|500|failed to connect',
        r'No results found|empty response',
        r'unable to retrieve|timed out'
    ]

    for pattern in hallucination_patterns:
        if re.search(pattern, task_output, re.IGNORECASE):
            print(f'🚨 HALLUCINATION: {pattern} in output')
            return {'hallucinated': True, 'pattern': pattern}
    return {'hallucinated': False}

from sklearn.feature_extraction.text import TfidfVectorizer
from sklearn.metrics.pairwise import cosine_similarity

def detect_task_drift(original_task, agent_output):
    vectorizer = TfidfVectorizer(stop_words='english')
    tfidf_matrix = vectorizer.fit_transform([original_task, agent_output])

    similarity = cosine_similarity(tfidf_matrix[0:1], tfidf_matrix[1:2])[0][0]

    if similarity < 0.3:
        print(f'🚨 TASK DRIFT: Semantic similarity {similarity:.2f} < 0.3 threshold')
        return {'drifted': True, 'similarity': similarity}
    return {'drifted': False, 'similarity': similarity}
